#include <bits/stdc++.h>
#pragma GCC optimize("O3")
using namespace std;

const int BASE = 1000000000;    // Mỗi khối lưu 9 chữ số.
const int MAX_BLOCKS = 500;     // Dự kiến đủ số khối cho số rất lớn.
const int maxn = 130;           // maxn dùng cho số chữ số + dự phòng.

struct BigInt {
    int a[MAX_BLOCKS]; // Mỗi phần tử lưu một khối (9 chữ số).
    int len;           // Số khối hiện có.
};

// Khởi tạo BigInt bằng 0.
void init(BigInt &x) {
    memset(x.a, 0, sizeof(x.a));
    x.len = 1;
}

// Khởi tạo BigInt với một giá trị nguyên.
void init(BigInt &x, int value) {
    memset(x.a, 0, sizeof(x.a));
    x.a[0] = value;
    x.len = 1;
}

// Hàm cộng BigInt: dest = dest + src.
void addBigInt(BigInt &dest, const BigInt &src) {
    int carry = 0;
    int maxLen = max(dest.len, src.len);
    for (int i = 0; i < maxLen || carry; i++) {
        if(i == dest.len) {
            dest.a[i] = 0;
            dest.len++;
        }
        long long cur = (long long)dest.a[i] + (i < src.len ? src.a[i] : 0) + carry;
        dest.a[i] = int(cur % BASE);
        carry = int(cur / BASE);
    }
}

// Hàm in BigInt ra màn hình.
void printBigInt(const BigInt &x) {
    // In khối cao nhất (không có số 0 dẫn đầu).
    printf("%d", x.a[x.len - 1]);
    // In các khối còn lại, phải đảm bảo đủ 9 chữ số.
    for (int i = x.len - 2; i >= 0; i--) {
        printf("%09d", x.a[i]);
    }
    printf("\n");
}

// Mảng DP sử dụng kiểu BigInt.
BigInt dp[maxn][maxn][2];

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);
    cout.tie(nullptr);

    int T;
    cin >> T;
    while (T--) {
        int n, m;
        cin >> n >> m;

        // Reset lại mảng dp cho mỗi test case.
        for (int i = 0; i < maxn; i++) {
            for (int j = 0; j < maxn; j++) {
                init(dp[i][j][0]);
                init(dp[i][j][1]);
            }
        }

        // Khởi tạo cho số có 1 chữ số (chữ số đầu không được là 0).
        for (int d = 1; d <= 9; d++) {
            if(d > m) break;
            int flag = (d == 1) ? 1 : 0;
            init(dp[1][d][flag], 1);
        }

        // Quy hoạch động: xây dựng số có độ dài từ 1 đến n.
        for (int len = 1; len < n; len++) {
            for (int sum = 0; sum <= m; sum++) {
                for (int flag = 0; flag < 2; flag++) {
                    // Nếu trạng thái hiện tại bằng 0, bỏ qua.
                    if(dp[len][sum][flag].len == 1 && dp[len][sum][flag].a[0] == 0)
                        continue;

                    // Nối thêm chữ số mới từ 0 đến 9.
                    for (int k = 0; k <= 9; k++) {
                        // Nếu chữ số trước là 1 và chữ số hiện tại là 3 thì bỏ qua (tránh xâu "13").
                        if(flag == 1 && k == 3) continue;
                        if(sum + k > m) continue; // Giữ tổng chữ số không vượt m.
                        int newFlag = (k == 1) ? 1 : 0;
                        addBigInt(dp[len+1][sum+k][newFlag], dp[len][sum][flag]);
                    }
                }
            }
        }

        // Tổng hợp các kết quả: số có 1 đến n chữ số và tổng các chữ số bằng m.
        BigInt answer;
        init(answer);
        for (int len = 1; len <= n; len++) {
            addBigInt(answer, dp[len][m][0]);
            addBigInt(answer, dp[len][m][1]);
        }

        printBigInt(answer);
    }

    return 0;
}
